/* 生成NPC, By BlackStar, Ver.0.1.0 */
(()=>{"use strict";const defaultConfig={maxtrait:2};const generateNPC=(names,attrs,traits,config={})=>{config=Object.assign({},defaultConfig,config);const firstname=names.first.random();const lastname=names.last.random();const npcAttrs={};for(const[key,{min:min,max:max}]of Object.entries(attrs)){npcAttrs[key]=randomInt(min,max)}const applies=[];const map={};let available=[...traits];let count=0;while(applies.length<config.maxtrait&&available.length>0){if(count>0){available=available.filter((trait=>{if(trait.exclusive){return!trait.exclusive.some((exclusive=>map[exclusive]!==undefined))}return true}))}if(available.length===0)break;const trait=available.random();if(!(trait.name in map)){applies.push(trait.name);map[trait.name]=trait;available=available.filter((t=>t!==trait))}count++}for(const trait of Object.values(map)){for(const[key,value]of Object.entries(trait.affects)){if(npcAttrs[key]!==undefined){npcAttrs[key]+=value}}}return{firstname:firstname,lastname:lastname,...npcAttrs,traits:applies}};setup.generateNPC=generateNPC;window.generateNPC=window.generateNPC||generateNPC})();
/* 生成NPC */